import { useQuery } from '@tanstack/react-query'
import React from 'react'
import { useParams } from 'react-router-dom'
import { Img_URL, fetchMovieDetails } from '../../utils/fetchApi'
import '../MovieItems/movie.scss'
const Movie = () => {
  const {id} = useParams()
  const{data:Movie}= useQuery({
    queryKey: ['Movie',`${id}`],
    queryFn: ()=> fetchMovieDetails(`${id}`)
    .then((res)=>{
      console.log(res.data);
      return res.data;
    })
  })

  return (
    <section className='movie' style={{backgroundImage:Movie.backdrop_path?`linear-gradient(rgba(0,0,0,0.4),rgba(0,0,0,0.4)),url(${`${Img_URL}${Movie.backdrop_path}`})`:'rgb(0,0,0)'}}>
      <div key={Movie.id}>
        <h1>{Movie.title}</h1>
        <p>{Movie.overview}</p>
        <p>Ratings:{Movie.vote_average}</p>
      </div>
    </section>
  )
}

export default Movie
